// ============================================================
// WF01 — Parse Airbnb email (v2 - adapte au format reel)
// IMPORTANT: utilise textHtml (pas html) pour IMAP v2
// ============================================================

var html = $input.first().json.textHtml || $input.first().json.html || "";
var subject = $input.first().json.subject || "";
var messageId = $input.first().json.messageId || "";

// --- Detection du type d email ---
// IMPORTANT: defaut = "unknown" — seuls les emails avec match positif sont traites
var emailType = "unknown";

// Annulation (tester en premier car prioritaire)
if (/annul/i.test(subject) || /cancel/i.test(subject)) {
  emailType = "cancellation";
}
// Modification
else if (/modifi/i.test(subject) || /updated/i.test(subject) || /changed/i.test(subject)) {
  emailType = "modification";
}
// "En attente" ou "demande" = inquiry (en attente de validation proprietaire)
else if (/en attente/i.test(subject) || /demande de r/i.test(subject) || /demande.*reservation/i.test(subject) || /reservation request/i.test(subject)) {
  emailType = "inquiry";
}
// Confirmation (match positif requis — sujet doit contenir un mot-cle reservation)
else if (/r[e\u00e9]serv/i.test(subject) || /confirm[e\u00e9]e?/i.test(subject) || /s[e\u00e9]jour/i.test(subject) || /booking confirm/i.test(subject)) {
  emailType = "confirmation";
}

// --- Extraction du nom du voyageur ---
var guestName = "";

// Pattern 1: "demande de Alexis" ou "demande de Jean Dupont"
var m = subject.match(/demande de ([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)/);
if (m) guestName = m[1].trim();

// Pattern 2: dans le HTML "demande de Alexis"
if (!guestName) {
  m = html.match(/demande de ([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)/);
  if (m) guestName = m[1].trim();
}

// Pattern 3: "a reserve" ou "a r\u00e9serv\u00e9"
if (!guestName) {
  m = html.match(/([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)\s+a\s+r[e\u00e9]serv/);
  if (m) guestName = m[1].trim();
}

// Pattern 4: aria-label avec un prenom
if (!guestName) {
  m = html.match(/aria-label="([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)"/);
  if (m) guestName = m[1].trim();
}

// Pattern 5: "Votre voyageur : Xxx"
if (!guestName) {
  m = html.match(/voyageur\s*:\s*([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)/i);
  if (m) guestName = m[1].trim();
}

// --- Extraction des dates ---
var moisFR = {
  "janv": "01", "janvier": "01", "jan": "01",
  "f\u00e9vr": "02", "fevr": "02", "f\u00e9vrier": "02", "fevrier": "02", "fev": "02", "feb": "02",
  "mars": "03", "mar": "03",
  "avr": "04", "avril": "04", "apr": "04",
  "mai": "05", "may": "05",
  "juin": "06", "jun": "06",
  "juil": "07", "juillet": "07", "jul": "07",
  "ao\u00fbt": "08", "aout": "08", "aug": "08",
  "sept": "09", "septembre": "09", "sep": "09",
  "oct": "10", "octobre": "10",
  "nov": "11", "novembre": "11",
  "d\u00e9c": "12", "d\u00e9cembre": "12", "dec": "12", "decembre": "12"
};

function getMonth(str) {
  var key = str.toLowerCase().replace(/\./g, "");
  return moisFR[key] || null;
}

var checkIn = "";
var checkOut = "";

// Pattern 1: format compact "19\u201320 f\u00e9vr. 2026" (jour\u2013jour mois annee)
m = subject.match(/(\d{1,2})\s*[\u2013\u2014-]\s*(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
if (!m) m = html.match(/(\d{1,2})\s*[\u2013\u2014-]\s*(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
if (m) {
  var month = getMonth(m[3]);
  if (month) {
    checkIn = m[4] + "-" + month + "-" + m[1].padStart(2, "0");
    checkOut = m[4] + "-" + month + "-" + m[2].padStart(2, "0");
  }
}

// Pattern 2: format complet "19 f\u00e9vr. 2026 \u2013 20 f\u00e9vr. 2026"
if (!checkIn) {
  m = (subject + " " + html).match(/(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})\s*[\u2013\u2014-]\s*(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
  if (m) {
    var m1 = getMonth(m[2]);
    var m2 = getMonth(m[5]);
    if (m1) checkIn = m[3] + "-" + m1 + "-" + m[1].padStart(2, "0");
    if (m2) checkOut = m[6] + "-" + m2 + "-" + m[4].padStart(2, "0");
  }
}

// Pattern 3: "Arriv\u00e9e" et "D\u00e9part" dans le HTML
if (!checkIn) {
  var arrM = html.match(/[Aa]rriv[e\u00e9]e[^<\d]*?(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
  var depM = html.match(/[Dd][e\u00e9]part[^<\d]*?(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
  if (arrM) {
    var am = getMonth(arrM[2]);
    if (am) checkIn = arrM[3] + "-" + am + "-" + arrM[1].padStart(2, "0");
  }
  if (depM) {
    var dm = getMonth(depM[2]);
    if (dm) checkOut = depM[3] + "-" + dm + "-" + depM[1].padStart(2, "0");
  }
}

// --- Extraction du nombre de voyageurs ---
var nbGuests = 1;
m = html.match(/(\d+)\s+voyageur/i);
if (!m) m = html.match(/(\d+)\s+guest/i);
if (!m) m = html.match(/voyageurs?\s*:\s*(\d+)/i);
if (m) nbGuests = parseInt(m[1], 10);

// --- Extraction du montant ---
var amount = null;
m = html.match(/[Tt]otal[^0-9\u20ac]*[\u20ac]?\s*([\d\s]+[.,]\d{2})\s*[\u20acEUR]?/);
if (!m) m = html.match(/[Rr]evenus?\s*:?\s*[\u20ac]?\s*([\d\s]+[.,]\d{2})/);
if (!m) m = html.match(/[\u20acEUR]\s*([\d\s]+[.,]\d{2})/);
if (!m) m = html.match(/([\d\s]+[.,]\d{2})\s*[\u20acEUR]/);
if (m) {
  amount = parseFloat(m[1].replace(/\s/g, "").replace(",", "."));
}

// --- Extraction de la reference Airbnb ---
// Format: HMXXXXXXXXXX dans les URLs
var platformRefId = "";
m = html.match(/reservations\/details\/(HM[A-Z0-9]+)/);
if (!m) m = html.match(/\b(HM[A-Z0-9]{6,12})\b/);
if (!m) m = subject.match(/\b(HM[A-Z0-9]{6,12})\b/);
if (!m) m = html.match(/[Cc]ode\s+de\s+confirmation\s*:?\s*([A-Z0-9]{8,14})/);
if (!m) m = html.match(/[Cc]onfirmation\s+code\s*:?\s*([A-Z0-9]{8,14})/);
if (m) platformRefId = m[1].trim();

// --- Extraction du nom de la propriete ---
var propertyName = "";

// Pattern 1: sujet "l annonce Villa Sidi Kaouki"
m = subject.match(/l'annonce\s+(.+?)\s+pour\s/i);
if (!m) m = subject.match(/annonce\s+(.+?)\s+pour\s/i);
if (!m) m = subject.match(/concernant\s+(.+?)\s+pour\s/i);

// Pattern 2: "votre logement X"
if (!m) m = html.match(/votre\s+(?:logement|bien|propri[e\u00e9]t[e\u00e9]|appartement|studio|maison|annonce)\s+([^<\n"]+)/i);

// Pattern 3: "Logement : X"
if (!m) m = html.match(/[Ll]ogement\s*:\s*([^<\n]+)/);

if (m) {
  propertyName = m[1].trim();
  // Nettoyer les guillemets
  propertyName = propertyName.replace(/["\u00ab\u00bb]/g, "").trim();
}

// --- Construction de l output ---
var result = {
  platform: "airbnb",
  emailType: emailType,
  guestName: guestName || "[NON DETECTE]",
  checkIn: checkIn || "[NON DETECTE]",
  checkOut: checkOut || "[NON DETECTE]",
  nbGuests: nbGuests,
  amount: amount,
  platformRefId: platformRefId || "[NON DETECTE]",
  propertyName: propertyName || "[NON DETECTE]",
  sourceEmailId: messageId,
  _parseQuality: {
    guestName: !!guestName,
    dates: !!(checkIn && checkOut),
    amount: amount !== null,
    reference: !!platformRefId,
    property: !!propertyName
  },
  _rawSubject: subject
};

var criticalFields = [guestName, checkIn, checkOut, platformRefId];
result._isPartialParse = criticalFields.some(function(f) { return !f; });

return [{json: result}];

// ============================================================
// WF01 — Parse Booking.com confirmation email
// Extrait les informations de reservation depuis le HTML
// ============================================================

const html = $input.first().json.html || '';
const subject = $input.first().json.subject || '';
const messageId = $input.first().json.messageId || '';

// --- Detection du type d'email ---
// IMPORTANT: defaut = 'unknown' — seuls les emails avec match positif sont traites
let emailType = 'unknown';

const cancelPatterns = [
  /annul(é|e|ation)/i,
  /cancel(led|lation)/i,
  /[Rr][ée]servation\s+annul[ée]e/i,
  /[Bb]ooking\s+cancell?ation/i,
];

const modifyPatterns = [
  /modifi(é|cation)/i,
  /mis(e)?\s+[àa]\s+jour/i,
  /updated/i,
  /changed/i,
  /changement/i,
];

for (const pattern of cancelPatterns) {
  if (pattern.test(subject) || pattern.test(html)) {
    emailType = 'cancellation';
    break;
  }
}

if (emailType === 'unknown') {
  for (const pattern of modifyPatterns) {
    if (pattern.test(subject) || pattern.test(html)) {
      emailType = 'modification';
      break;
    }
  }
}

const inquiryPatterns = [
  /demande de r[ée]servation/i,
  /reservation request/i,
  /en attente de confirmation/i,
  /en attente de validation/i,
  /pending confirmation/i,
  /awaiting.*confirmation/i,
  /demande.*en attente/i,
];

if (emailType === 'unknown') {
  for (const pattern of inquiryPatterns) {
    if (pattern.test(subject) || pattern.test(html)) {
      emailType = 'inquiry';
      break;
    }
  }
}

const confirmationPatterns = [
  /r[ée]serv/i,
  /confirm[ée]e?/i,
  /s[ée]jour/i,
  /nouvelle? r[ée]servation/i,
  /new booking/i,
];

if (emailType === 'unknown') {
  for (const pattern of confirmationPatterns) {
    if (pattern.test(subject) || pattern.test(html)) {
      emailType = 'confirmation';
      break;
    }
  }
}

// --- Extraction du nom du voyageur ---
// Booking FR : "Nouvelle réservation de Jean Dupont"
// Booking EN : "New booking from Jean Dupont"
// Booking : "Nom du client : Jean Dupont"
let guestName = '';

const guestPatterns = [
  // "Nom du client : Jean Dupont" ou "Guest name: Jean Dupont"
  /[Nn]om\s+du\s+client\s*:\s*([A-ZÀ-Ü][a-zà-ü]+(?:\s+[A-ZÀ-Ü][a-zà-ü]+)+)/,
  /[Gg]uest\s+name\s*:\s*([A-Z][a-z]+(?:\s+[A-Z][a-z]+)+)/,
  // "réservation de Jean Dupont"
  /r[ée]servation\s+de\s+([A-ZÀ-Ü][a-zà-ü]+(?:\s+[A-ZÀ-Ü][a-zà-ü]+)+)/,
  // "booking from Jean Dupont"
  /booking\s+from\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+)+)/i,
  // Dans le HTML
  /class="[^"]*guest[_-]?name[^"]*"[^>]*>([^<]+)</i,
  // "Client : Jean Dupont"
  /[Cc]lient\s*:\s*([A-ZÀ-Ü][a-zà-ü]+(?:\s+[A-ZÀ-Ü][a-zà-ü]+)+)/,
  // Sujet : "Confirmation — Jean Dupont"
  /[Cc]onfirmation\s*[-–—]\s*([A-ZÀ-Ü][a-zà-ü]+(?:\s+[A-ZÀ-Ü][a-zà-ü]+)+)/,
];

for (const pattern of guestPatterns) {
  const match = html.match(pattern) || subject.match(pattern);
  if (match) {
    guestName = match[1].trim();
    break;
  }
}

// --- Extraction des dates ---
// Booking utilise souvent : "Arrivée : lun. 15 mars 2026" et "Départ : jeu. 18 mars 2026"
// Ou en format compact : "15 mars 2026 — 18 mars 2026"
// Ou "Check-in: 2026-03-15" "Check-out: 2026-03-18"

const moisFR = {
  'janv': '01', 'janvier': '01', 'jan': '01',
  'févr': '02', 'février': '02', 'fevr': '02', 'fevrier': '02', 'fev': '02', 'feb': '02',
  'mars': '03', 'mar': '03',
  'avr': '04', 'avril': '04', 'apr': '04',
  'mai': '05', 'may': '05',
  'juin': '06', 'jun': '06',
  'juil': '07', 'juillet': '07', 'jul': '07',
  'août': '08', 'aout': '08', 'aug': '08',
  'sept': '09', 'septembre': '09', 'sep': '09',
  'oct': '10', 'octobre': '10',
  'nov': '11', 'novembre': '11',
  'déc': '12', 'décembre': '12', 'dec': '12', 'decembre': '12',
};

function parseDateFR(dateStr) {
  // Format "15 mars 2026" ou "lun. 15 mars 2026"
  const match = dateStr.match(/(\d{1,2})\s+([\wéûô]+)\.?\s+(\d{4})/);
  if (match) {
    const day = match[1].padStart(2, '0');
    const monthKey = match[2].toLowerCase().replace(/\./g, '');
    const month = moisFR[monthKey];
    const year = match[3];
    if (month) return `${year}-${month}-${day}`;
  }
  // Format YYYY-MM-DD
  const matchISO = dateStr.match(/(\d{4})-(\d{2})-(\d{2})/);
  if (matchISO) return matchISO[0];
  // Format DD/MM/YYYY
  const matchSlash = dateStr.match(/(\d{2})\/(\d{2})\/(\d{4})/);
  if (matchSlash) return `${matchSlash[3]}-${matchSlash[2]}-${matchSlash[1]}`;
  return null;
}

let checkIn = '';
let checkOut = '';

// Pattern 1 : "Arrivée ... date" et "Départ ... date"
const arrivalPattern = /[Aa]rriv[ée]e[^<\d]*?(\d{1,2}\s+[\wéûô]+\.?\s+\d{4})/;
const departurePattern = /[Dd][ée]part[^<\d]*?(\d{1,2}\s+[\wéûô]+\.?\s+\d{4})/;

// Pattern 2 : "Check-in ... date" et "Check-out ... date"
const checkinPattern = /[Cc]heck[\s-]?in[^<\d]*?(\d{1,2}\s+[\wéûô]+\.?\s+\d{4}|\d{4}-\d{2}-\d{2})/;
const checkoutPattern = /[Cc]heck[\s-]?out[^<\d]*?(\d{1,2}\s+[\wéûô]+\.?\s+\d{4}|\d{4}-\d{2}-\d{2})/;

// Pattern 3 : plage de dates "15 mars 2026 — 18 mars 2026"
const dateRangePattern = /(\d{1,2}\s+[\wéûô]+\.?\s+\d{4})\s*[-–—]\s*(\d{1,2}\s+[\wéûô]+\.?\s+\d{4})/;

let arrMatch = html.match(arrivalPattern);
let depMatch = html.match(departurePattern);

if (arrMatch && depMatch) {
  checkIn = parseDateFR(arrMatch[1]);
  checkOut = parseDateFR(depMatch[1]);
} else {
  arrMatch = html.match(checkinPattern);
  depMatch = html.match(checkoutPattern);
  if (arrMatch && depMatch) {
    checkIn = parseDateFR(arrMatch[1]);
    checkOut = parseDateFR(depMatch[1]);
  } else {
    const rangeMatch = html.match(dateRangePattern);
    if (rangeMatch) {
      checkIn = parseDateFR(rangeMatch[1]);
      checkOut = parseDateFR(rangeMatch[2]);
    }
  }
}

// --- Extraction du nombre de voyageurs ---
let nbGuests = 1;

const guestsPatterns = [
  /(\d+)\s+(?:voyageur|adulte|personne|guest|occupant)/i,
  /[Nn]ombre\s+de\s+(?:voyageur|personne|client)s?\s*:\s*(\d+)/,
  /[Gg]uests?\s*:\s*(\d+)/,
  /[Oo]ccupants?\s*:\s*(\d+)/,
];

for (const pattern of guestsPatterns) {
  const match = html.match(pattern);
  if (match) {
    nbGuests = parseInt(match[1] || match[2], 10);
    break;
  }
}

// --- Extraction du montant ---
// Booking FR : "Prix total : 450,00 EUR" ou "Montant : € 450,00"
// Booking EN : "Total price: EUR 450.00" ou "€ 450.00"
let amount = null;

const amountPatterns = [
  /[Pp]rix\s+total\s*:?\s*[€]?\s*([\d\s]+[.,]\d{2})\s*(?:EUR|€)?/,
  /[Tt]otal\s+(?:price|amount)\s*:?\s*(?:EUR|€)?\s*([\d\s]+[.,]\d{2})/,
  /[Mm]ontant\s+total\s*:?\s*(?:EUR|€)?\s*([\d\s]+[.,]\d{2})/,
  /[Cc]ommission[^€\d]*(?:EUR|€)\s*([\d\s]+[.,]\d{2})/,
  /(?:EUR|€)\s*([\d\s]+[.,]\d{2})/,
  /([\d\s]+[.,]\d{2})\s*(?:EUR|€)/,
];

for (const pattern of amountPatterns) {
  const match = html.match(pattern);
  if (match) {
    amount = parseFloat(match[1].replace(/\s/g, '').replace(',', '.'));
    break;
  }
}

// --- Extraction du numero de confirmation Booking ---
// Format Booking : numero a 9-10 chiffres ou format "12345678.1"
let platformRefId = '';

const refPatterns = [
  // "Numéro de confirmation : 1234567890"
  /[Nn]um[ée]ro\s+de\s+confirmation\s*:\s*(\d{7,12}(?:\.\d+)?)/,
  // "Confirmation number: 1234567890"
  /[Cc]onfirmation\s+number\s*:\s*(\d{7,12}(?:\.\d+)?)/,
  // "Réf. : 1234567890"
  /[Rr][ée]f\.?\s*:\s*(\d{7,12}(?:\.\d+)?)/,
  // "Booking reference: 1234567890"
  /[Bb]ooking\s+reference\s*:\s*(\d{7,12}(?:\.\d+)?)/,
  // Numero seul dans un element HTML specifique
  /class="[^"]*(?:confirmation|booking)[_-]?(?:number|ref)[^"]*"[^>]*>(\d{7,12}(?:\.\d+)?)</i,
  // Dans le sujet : "Confirmation #1234567890"
  /[Cc]onfirmation\s*#?\s*(\d{7,12})/,
];

for (const pattern of refPatterns) {
  const match = html.match(pattern) || subject.match(pattern);
  if (match) {
    platformRefId = match[1].trim();
    break;
  }
}

// --- Extraction du nom de la propriete ---
let propertyName = '';

const propertyPatterns = [
  // "Nom de l'hébergement : Villa Sidi Kaouki"
  /[Nn]om\s+de\s+l'(?:hébergement|h[ée]bergement|logement)\s*:\s*([^<\n]+)/,
  // "Property: Villa Sidi Kaouki"
  /[Pp]roperty\s*:\s*([^<\n]+)/,
  // "pour Villa Sidi Kaouki"
  /pour\s+(?:le\s+|votre\s+)?([A-ZÀ-Ü][^<,\n]{2,40}?)(?:\s+[àa]\s+|\s*,|\s*<)/,
  // "Reservation at Villa Sidi Kaouki"
  /(?:at|pour|chez)\s+([A-ZÀ-Ü][^<,\n]{2,40}?)(?:\s*[-–,<]|\s*$)/i,
  // Dans le sujet
  /(?:pour|at|chez)\s+([A-ZÀ-Ü][^<,\n]{2,40})/i,
];

for (const pattern of propertyPatterns) {
  const match = html.match(pattern) || subject.match(pattern);
  if (match) {
    propertyName = match[1].trim();
    break;
  }
}

// --- Construction de l'output ---
const result = {
  platform: 'booking',
  emailType,
  guestName: guestName || '[NON DETECTE]',
  checkIn: checkIn || '[NON DETECTE]',
  checkOut: checkOut || '[NON DETECTE]',
  nbGuests,
  amount,
  platformRefId: platformRefId || '[NON DETECTE]',
  propertyName: propertyName || '[NON DETECTE]',
  sourceEmailId: messageId,
  _parseQuality: {
    guestName: !!guestName,
    dates: !!(checkIn && checkOut),
    amount: amount !== null,
    reference: !!platformRefId,
    property: !!propertyName,
  },
  _rawSubject: subject,
};

const criticalFields = [guestName, checkIn, checkOut, platformRefId];
result._isPartialParse = criticalFields.some(f => !f);

return [{json: result}];

// Log l'email non reconnu et preparer l'alerte
const from = $input.first().json.from || 'inconnu';
const subject = $input.first().json.subject || '(sans sujet)';
const date = $input.first().json.date || new Date().toISOString();

return [{
  json: {
    alertType: 'unknown_email',
    from,
    subject,
    date,
    message: `Email non reconnu recu de ${from} : "${subject}"`,
  }
}];

// Preparer le payload pour l'API webhook
const data = $input.first().json;

return [{
  json: {
    platform: data.platform,
    platformRefId: data.platformRefId,
    propertyName: data.propertyName,
    guestName: data.guestName,
    checkIn: data.checkIn,
    checkOut: data.checkOut,
    nbGuests: data.nbGuests,
    amount: data.amount,
    currency: 'EUR',
    status: 'confirmed',
    sourceType: 'email_parse',
    sourceEmailId: data.sourceEmailId,
  }
}];

// Preparer le payload pour l'API webhook (modification)
const data = $input.first().json;

return [{
  json: {
    platform: data.platform,
    platformRefId: data.platformRefId,
    propertyName: data.propertyName,
    guestName: data.guestName,
    checkIn: data.checkIn,
    checkOut: data.checkOut,
    nbGuests: data.nbGuests,
    amount: data.amount,
    currency: 'EUR',
    status: 'confirmed',
    sourceType: 'email_parse',
    sourceEmailId: data.sourceEmailId,
